/**
 * User Repository
 *
 * Data access layer for User entities.
 * Handles both tenant-scoped users and platform users.
 *
 * @module modules/_core/user/user.repository
 *
 * @example
 * ```typescript
 * import { UserRepository } from '@/modules/_core/user/user.repository';
 *
 * const repo = container.resolve('UserRepository');
 * const user = await repo.findByEmail('user@example.com');
 * ```
 */

import { injectable, inject } from 'tsyringe';
import { PrismaClient, UserStatus, Prisma } from '@prisma/client';

import { TOKENS } from '@/core/kernel/container';
import { AppException } from '@/core/exceptions/app.exception';
import { notDeleted, softDelete } from '@/config/database';

import type {
  User,
  UserWithRelations,
  UserListParams,
  UserSummary,
} from '@/modules/_core/user/user.types';

// -----------------------------------------------------------------------------
// Types
// -----------------------------------------------------------------------------

/**
 * Paginated result type
 */
export interface PaginatedResult<T> {
  /** Array of entities */
  data: T[];
  /** Pagination metadata */
  meta: {
    page: number;
    perPage: number;
    total: number;
    totalPages: number;
  };
}

/**
 * Create user data (input for repository)
 */
export interface CreateUserData {
  email: string;
  passwordHash: string;
  firstName: string;
  lastName: string;
  phone?: string | null;
  avatar?: string | null;
  status?: UserStatus;
  organizationId?: string | null;
  emailVerifiedAt?: Date | null;
}

/**
 * Update user data (input for repository)
 */
export interface UpdateUserData {
  email?: string;
  passwordHash?: string;
  firstName?: string;
  lastName?: string;
  phone?: string | null;
  avatar?: string | null;
  status?: UserStatus;
  emailVerifiedAt?: Date | null;
  lastLoginAt?: Date | null;
}

// -----------------------------------------------------------------------------
// Constants
// -----------------------------------------------------------------------------

const DEFAULT_PER_PAGE = 20;
const MAX_PER_PAGE = 100;

// -----------------------------------------------------------------------------
// User Repository
// -----------------------------------------------------------------------------

/**
 * Repository for User entity operations.
 *
 * Handles all database operations for users including:
 * - CRUD operations
 * - Email lookups
 * - Role assignments
 * - Pagination and search
 *
 * @remarks
 * Users can be organization-scoped (with organizationId) or
 * platform-level (with null organizationId).
 * Soft delete is enforced on all operations.
 *
 * @example
 * ```typescript
 * @injectable()
 * class UserService {
 *   constructor(
 *     @inject('UserRepository') private repo: UserRepository
 *   ) {}
 *
 *   async getByEmail(email: string) {
 *     return this.repo.findByEmail(email);
 *   }
 * }
 * ```
 */
@injectable()
export class UserRepository {
  constructor(
    @inject(TOKENS.PrismaClient) private readonly prisma: PrismaClient
  ) {}

  // ---------------------------------------------------------------------------
  // Read Operations
  // ---------------------------------------------------------------------------

  /**
   * Finds all users for an organization with pagination and filtering
   *
   * @param organizationId - Organization ID to filter by
   * @param params - Query parameters (pagination, sorting, filtering)
   * @returns Paginated list of users
   *
   * @example
   * ```typescript
   * const result = await repo.findAllByOrganization('org_123', {
   *   page: 1,
   *   perPage: 10,
   *   status: 'ACTIVE',
   *   sortBy: 'createdAt',
   * });
   * ```
   */
  async findAllByOrganization(
    organizationId: string,
    params: UserListParams = {}
  ): Promise<PaginatedResult<User>> {
    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      status,
      roleId,
      search,
      emailVerified,
      createdAfter,
      createdBefore,
      includeDeleted = false,
      sortBy = 'createdAt',
      sortOrder = 'desc',
    } = params;

    // Normalize pagination
    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    // Build where clause
    const where: Prisma.UserWhereInput = {
      organizationId,
      ...(includeDeleted ? {} : notDeleted),
      ...(status && { status }),
      ...(search && {
        OR: [
          { email: { contains: search, mode: 'insensitive' } },
          { firstName: { contains: search, mode: 'insensitive' } },
          { lastName: { contains: search, mode: 'insensitive' } },
        ],
      }),
      ...(emailVerified !== undefined && {
        emailVerifiedAt: emailVerified ? { not: null } : null,
      }),
      ...(createdAfter && { createdAt: { gte: createdAfter } }),
      ...(createdBefore && { createdAt: { lte: createdBefore } }),
      ...(roleId && {
        userRoles: {
          some: { roleId },
        },
      }),
    };

    // Build orderBy
    const orderBy: Prisma.UserOrderByWithRelationInput = {
      [sortBy]: sortOrder,
    };

    // Execute count and find in parallel
    const [total, data] = await Promise.all([
      this.prisma.user.count({ where }),
      this.prisma.user.findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data: data as User[],
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds all platform users (no organization) with pagination
   *
   * @param params - Query parameters
   * @returns Paginated list of platform users
   */
  async findAllPlatformUsers(params: UserListParams = {}): Promise<PaginatedResult<User>> {
    const {
      page = 1,
      perPage = DEFAULT_PER_PAGE,
      status,
      search,
      includeDeleted = false,
      sortBy = 'createdAt',
      sortOrder = 'desc',
    } = params;

    const normalizedPerPage = Math.min(Math.max(1, perPage), MAX_PER_PAGE);
    const normalizedPage = Math.max(1, page);
    const skip = (normalizedPage - 1) * normalizedPerPage;

    const where: Prisma.UserWhereInput = {
      organizationId: null,
      ...(includeDeleted ? {} : notDeleted),
      ...(status && { status }),
      ...(search && {
        OR: [
          { email: { contains: search, mode: 'insensitive' } },
          { firstName: { contains: search, mode: 'insensitive' } },
          { lastName: { contains: search, mode: 'insensitive' } },
        ],
      }),
    };

    const orderBy: Prisma.UserOrderByWithRelationInput = {
      [sortBy]: sortOrder,
    };

    const [total, data] = await Promise.all([
      this.prisma.user.count({ where }),
      this.prisma.user.findMany({
        where,
        orderBy,
        skip,
        take: normalizedPerPage,
      }),
    ]);

    return {
      data: data as User[],
      meta: {
        page: normalizedPage,
        perPage: normalizedPerPage,
        total,
        totalPages: Math.ceil(total / normalizedPerPage),
      },
    };
  }

  /**
   * Finds all users as summaries (for dropdowns, etc.)
   *
   * @param organizationId - Organization ID to filter by
   * @param params - Optional filtering params
   * @returns Array of user summaries
   */
  async findAllSummaries(
    organizationId: string,
    params: Partial<UserListParams> = {}
  ): Promise<UserSummary[]> {
    const { status, includeDeleted = false } = params;

    const where: Prisma.UserWhereInput = {
      organizationId,
      ...(includeDeleted ? {} : notDeleted),
      ...(status && { status }),
    };

    const users = await this.prisma.user.findMany({
      where,
      select: {
        id: true,
        email: true,
        firstName: true,
        lastName: true,
        avatar: true,
        status: true,
        lastLoginAt: true,
        createdAt: true,
        userRoles: {
          select: {
            role: {
              select: {
                name: true,
              },
            },
          },
          take: 1,
          orderBy: { assignedAt: 'asc' },
        },
        _count: {
          select: {
            userRoles: true,
          },
        },
      },
      orderBy: { firstName: 'asc' },
    });

    return users.map((user) => ({
      id: user.id,
      email: user.email,
      fullName: `${user.firstName} ${user.lastName}`.trim(),
      avatar: user.avatar,
      status: user.status,
      primaryRole: user.userRoles[0]?.role.name,
      roleCount: user._count.userRoles,
      lastLoginAt: user.lastLoginAt,
      createdAt: user.createdAt,
    }));
  }

  /**
   * Finds a user by ID
   *
   * @param id - User ID
   * @returns User or null
   */
  async findById(id: string): Promise<User | null> {
    const result = await this.prisma.user.findFirst({
      where: { id, ...notDeleted },
    });

    return result as User | null;
  }

  /**
   * Finds a user by ID with tenant verification
   *
   * @param id - User ID
   * @param organizationId - Organization ID to verify
   * @returns User or null
   */
  async findByIdInOrganization(id: string, organizationId: string): Promise<User | null> {
    const result = await this.prisma.user.findFirst({
      where: { id, organizationId, ...notDeleted },
    });

    return result as User | null;
  }

  /**
   * Finds a user by ID with relations
   *
   * @param id - User ID
   * @returns User with relations or null
   */
  async findByIdWithRelations(id: string): Promise<UserWithRelations | null> {
    const result = await this.prisma.user.findFirst({
      where: { id, ...notDeleted },
      include: {
        organization: {
          select: {
            id: true,
            name: true,
            slug: true,
          },
        },
        userRoles: {
          include: {
            role: {
              select: {
                id: true,
                name: true,
                displayName: true,
                scope: true,
              },
            },
          },
        },
        _count: {
          select: {
            userRoles: true,
            sessions: true,
          },
        },
      },
    });

    return result as UserWithRelations | null;
  }

  /**
   * Finds a user by ID or throws
   *
   * @param id - User ID
   * @returns User
   * @throws {AppException} If not found
   */
  async findByIdOrThrow(id: string): Promise<User> {
    const user = await this.findById(id);

    if (!user) {
      throw AppException.notFound('User', id);
    }

    return user;
  }

  /**
   * Finds a user by email
   *
   * @param email - User email
   * @returns User or null
   */
  async findByEmail(email: string): Promise<User | null> {
    const result = await this.prisma.user.findFirst({
      where: { email: email.toLowerCase(), ...notDeleted },
    });

    return result as User | null;
  }

  /**
   * Finds a user by email or throws
   *
   * @param email - User email
   * @returns User
   * @throws {AppException} If not found
   */
  async findByEmailOrThrow(email: string): Promise<User> {
    const user = await this.findByEmail(email);

    if (!user) {
      throw AppException.notFound('User', email);
    }

    return user;
  }

  /**
   * Checks if an email exists
   *
   * @param email - Email to check
   * @param excludeId - Optional ID to exclude from check
   * @returns True if email exists
   */
  async emailExists(email: string, excludeId?: string): Promise<boolean> {
    const count = await this.prisma.user.count({
      where: {
        email: email.toLowerCase(),
        ...notDeleted,
        ...(excludeId && { id: { not: excludeId } }),
      },
    });

    return count > 0;
  }

  /**
   * Counts users in an organization
   *
   * @param organizationId - Organization ID
   * @param status - Optional status filter
   * @returns Count
   */
  async countByOrganization(organizationId: string, status?: UserStatus): Promise<number> {
    return this.prisma.user.count({
      where: {
        organizationId,
        ...notDeleted,
        ...(status && { status }),
      },
    });
  }

  /**
   * Gets user roles
   *
   * @param userId - User ID
   * @returns Array of role information
   */
  async getUserRoles(userId: string): Promise<Array<{
    roleId: string;
    roleName: string;
    roleDisplayName: string;
  }>> {
    const userRoles = await this.prisma.userRole.findMany({
      where: { userId },
      include: {
        role: {
          select: {
            id: true,
            name: true,
            displayName: true,
          },
        },
      },
    });

    return userRoles.map((ur) => ({
      roleId: ur.role.id,
      roleName: ur.role.name,
      roleDisplayName: ur.role.displayName,
    }));
  }

  // ---------------------------------------------------------------------------
  // Write Operations
  // ---------------------------------------------------------------------------

  /**
   * Creates a new user
   *
   * @param data - Create data
   * @returns Created user
   */
  async create(data: CreateUserData): Promise<User> {
    const result = await this.prisma.user.create({
      data: {
        email: data.email.toLowerCase(),
        passwordHash: data.passwordHash,
        firstName: data.firstName,
        lastName: data.lastName,
        phone: data.phone || null,
        avatar: data.avatar || null,
        status: data.status || UserStatus.ACTIVE,
        organizationId: data.organizationId || null,
        emailVerifiedAt: data.emailVerifiedAt || null,
      },
    });

    return result as User;
  }

  /**
   * Updates a user
   *
   * @param id - User ID
   * @param data - Update data
   * @returns Updated user
   * @throws {AppException} If not found
   */
  async update(id: string, data: UpdateUserData): Promise<User> {
    // Verify exists
    await this.findByIdOrThrow(id);

    const result = await this.prisma.user.update({
      where: { id },
      data: {
        ...(data.email !== undefined && { email: data.email.toLowerCase() }),
        ...(data.passwordHash !== undefined && { passwordHash: data.passwordHash }),
        ...(data.firstName !== undefined && { firstName: data.firstName }),
        ...(data.lastName !== undefined && { lastName: data.lastName }),
        ...(data.phone !== undefined && { phone: data.phone }),
        ...(data.avatar !== undefined && { avatar: data.avatar }),
        ...(data.status !== undefined && { status: data.status }),
        ...(data.emailVerifiedAt !== undefined && { emailVerifiedAt: data.emailVerifiedAt }),
        ...(data.lastLoginAt !== undefined && { lastLoginAt: data.lastLoginAt }),
      },
    });

    return result as User;
  }

  /**
   * Updates user status
   *
   * @param id - User ID
   * @param status - New status
   * @returns Updated user
   */
  async updateStatus(id: string, status: UserStatus): Promise<User> {
    await this.findByIdOrThrow(id);

    const result = await this.prisma.user.update({
      where: { id },
      data: { status },
    });

    return result as User;
  }

  /**
   * Updates user's last login timestamp
   *
   * @param id - User ID
   * @returns Updated user
   */
  async updateLastLogin(id: string): Promise<User> {
    const result = await this.prisma.user.update({
      where: { id },
      data: { lastLoginAt: new Date() },
    });

    return result as User;
  }

  /**
   * Verifies user email
   *
   * @param id - User ID
   * @returns Updated user
   */
  async verifyEmail(id: string): Promise<User> {
    const result = await this.prisma.user.update({
      where: { id },
      data: { emailVerifiedAt: new Date() },
    });

    return result as User;
  }

  // ---------------------------------------------------------------------------
  // Role Operations
  // ---------------------------------------------------------------------------

  /**
   * Assigns a role to a user
   *
   * @param userId - User ID
   * @param roleId - Role ID
   * @param assignedById - ID of user assigning the role
   * @returns True if assigned successfully
   */
  async assignRole(
    userId: string,
    roleId: string,
    assignedById?: string
  ): Promise<boolean> {
    // Check if already assigned
    const existing = await this.prisma.userRole.findUnique({
      where: { userId_roleId: { userId, roleId } },
    });

    if (existing) {
      return false; // Already assigned
    }

    await this.prisma.userRole.create({
      data: {
        userId,
        roleId,
        assignedById,
      },
    });

    return true;
  }

  /**
   * Removes a role from a user
   *
   * @param userId - User ID
   * @param roleId - Role ID
   * @returns True if removed successfully
   */
  async removeRole(userId: string, roleId: string): Promise<boolean> {
    const existing = await this.prisma.userRole.findUnique({
      where: { userId_roleId: { userId, roleId } },
    });

    if (!existing) {
      return false; // Not assigned
    }

    await this.prisma.userRole.delete({
      where: { userId_roleId: { userId, roleId } },
    });

    return true;
  }

  /**
   * Checks if user has a specific role
   *
   * @param userId - User ID
   * @param roleId - Role ID
   * @returns True if user has the role
   */
  async hasRole(userId: string, roleId: string): Promise<boolean> {
    const count = await this.prisma.userRole.count({
      where: { userId, roleId },
    });

    return count > 0;
  }

  /**
   * Checks if user has a role by name
   *
   * @param userId - User ID
   * @param roleName - Role name
   * @returns True if user has the role
   */
  async hasRoleByName(userId: string, roleName: string): Promise<boolean> {
    const count = await this.prisma.userRole.count({
      where: {
        userId,
        role: { name: roleName },
      },
    });

    return count > 0;
  }

  // ---------------------------------------------------------------------------
  // Delete Operations
  // ---------------------------------------------------------------------------

  /**
   * Soft deletes a user
   *
   * @param id - User ID
   * @returns Deleted user
   * @throws {AppException} If not found
   */
  async softDelete(id: string): Promise<User> {
    await this.findByIdOrThrow(id);

    const result = await this.prisma.user.update({
      where: { id },
      data: softDelete(),
    });

    return result as User;
  }

  /**
   * Restores a soft-deleted user
   *
   * @param id - User ID
   * @returns Restored user
   */
  async restore(id: string): Promise<User> {
    // Find including deleted
    const user = await this.prisma.user.findFirst({
      where: { id },
    });

    if (!user) {
      throw AppException.notFound('User', id);
    }

    const result = await this.prisma.user.update({
      where: { id },
      data: { deletedAt: null },
    });

    return result as User;
  }
}
